import{_ as i,c as l,o,ak as r}from"./chunks/framework.CYxz2ou1.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"NanoLife/A-书架/1-读书笔记/202303-软技能-代码之外的生存指南.md","filePath":"NanoLife/A-书架/1-读书笔记/202303-软技能-代码之外的生存指南.md","lastUpdated":1775467143000}'),n={name:"NanoLife/A-书架/1-读书笔记/202303-软技能-代码之外的生存指南.md"};function a(s,t,e,_,g,d){return o(),l("div",null,[...t[0]||(t[0]=[r('<h2 id="📘-基本信息" tabindex="-1">📘 基本信息 <a class="header-anchor" href="#📘-基本信息" aria-label="Permalink to &quot;📘 基本信息&quot;">​</a></h2><ul><li>📘 <strong>书名：软技能-代码之外的生存指南</strong></li><li>🕵️‍♂️ <strong>作者</strong>：<strong>约翰 * 森梅兹</strong></li><li>🥂 <strong>推荐分数</strong>：7</li><li>⏰ <strong>阅读时间</strong>：2023 年 3 月</li></ul><p>![[Pasted image 20260405150419.png|208]]</p><h2 id="📝-总结" tabindex="-1">📝 总结 <a class="header-anchor" href="#📝-总结" aria-label="Permalink to &quot;📝 总结&quot;">​</a></h2><p>一本非技术书籍，其实不只是给程序员看的，各种行业都很适用。部分章节并不是很需要看。</p><h2 id="📖-摘录" tabindex="-1">📖 摘录 <a class="header-anchor" href="#📖-摘录" aria-label="Permalink to &quot;📖 摘录&quot;">​</a></h2><ul><li>如果你想成为一名出色的软件开发人员，就得学会高效地与他人相处(即使写代码是你工作当中最为享受的一部分)。作为一个软件开发人员，你的工作就是与人打交道(其实几乎所有的职业都是这样)。</li><li><strong>专业化很重要</strong>。有大量的软件开发人员并没有具体的专业方向。更细分的专业领域常常比全能更受欢迎。</li><li><strong>承担责任</strong>。在任何公司里能让你脱颖而出的最重要法宝就是承担更多的责任。金钱总是追随着责任。有任何机会去承担更多责任时，承担起来!</li><li><strong>引人注目</strong>。如果你一直默默无闻，你的成就不为人知的话，即使你是团队中最聪明，最努力，最出色的开发人员，那也一文不名。如果找不到方法让你的老板或高层管理人员知道你在做什么，那你的所有努力都是徒劳的。技术上也是，如果没有宣传自己，自己再牛逼别人也不会知道。</li><li><strong>自学</strong>。不要只学软件开发。如果你把目标设定为更高级别的岗位甚至是行政岗位，你还需要学习领导力，管理和商科的相关知识。千万不要忘记分享自己学到的东西，这是实现&quot;引人注目&quot;的一种方式。</li><li><strong>追求品质，完善自我</strong>。专业人士是通过持续不断的自我完善达到自己所追求的高品质的。如果你也想成为专业人士，就要致力于持续不断地完善自己的技能，学习更多与专业相关的匠艺，确保自己制订并执行了学习计划，拓展自己的技能，学习新东西，这将有助于你做得更好。不要沾沾自喜，永远对努力成为更好的自己心存渴望。</li><li><strong>请勿陷入对技术的狂热之中</strong>。如果你能让自己不成为某种技术的信徒，你会在职业生涯之路上走得更远。</li><li><strong>伟大的音乐家和超级巨星之间的真正区别无非就是营销而已</strong>。程序员也需要自我营销。你也许是世界上最有天赋的软件开发人员，但是如果没有人知道你的存在，你也只不过是浮云一片。营销方式：演讲，博客等。</li><li>作为一名软件开发人员，可以用来推销自己的最佳媒介之一就是博客。我坚信每一个在乎自己职业生涯的软件开发人员都应该投资创建一个博客。博客是推销自己的一种既廉价又简单的方式，对于让自己声名鹊起极具价值。成功的博客每天能够吸引数百甚至数千的访客，这可以给你带来很多机会，从工作岗位到咨询项目，甚至是产品销售的目标客户。打造成功博客的最大秘诀有且仅有一个——持之以恒。我和许多成功的博主都谈论过，他们都有一个共同点——写了很多博客。我认识的一些最成功的博主每天都要写博客，而且已经坚持了许多年。</li><li><strong>关于学习</strong>。学习知识的最好方式就是立即将其用于实践，即使你还不知道自己在做什么。</li><li><strong>一切始于专注</strong>。</li><li><strong>产量多只表明生产效率高，只有完成正确的工作才会成为高效的人</strong>。</li><li>番茄工作法的基本思路：你规划出打算一天之内完成的工作，然后设置一个时长 25 分钟的定时器，去完成计划中的第一项任务; 在这 25 分钟之内，你只专注于这一项任务，心无旁骛。一旦有干扰，可以用各种方法屏蔽掉干扰，但是通常你要努力保证自己完全不被打扰。总之，你不希望自己的专注的工作状态被打断。番茄工作法只有被当作估算和评估工作的工具使用时，才能发挥它的真正威力。通过跟踪自己在一天内完成了多少个番茄钟，以及为每天要完成的番茄钟的数量设定目标，你瞬间有能力去真正评估自己每日工作的努力程度，也能知晓自己的工作能力。</li><li>自我控制是一门自我激励的艺术，而自我激励的核心则是自我责任感。如果你想不再依赖别人的影响，获得稳定，可预测的结果，你就要学会对自己负责。</li><li><strong>培养习惯</strong>：刷新你的代码。</li><li>成就我们的恰恰就是那些不断重复做的事情。因此，优秀不是一种行为，而是一种习惯。</li><li>为什么你需要跑步。跑步并不是增强心脏，增加肺活量的唯一方法，任何形式的运动都能做到这一点，但是跑步却是最容易的。它简单到无论你在哪里只需要出门跑就行了。</li></ul>',7)])])}const p=i(n,[["render",a]]);export{h as __pageData,p as default};
